UPDATE lessons SET code_lang='javascript', code_sample=E'console.log("Привет из JavaScript!");', code_output=E'Привет из JavaScript!' WHERE course_id='javascript' AND position=1;
UPDATE lessons SET code_lang='javascript', code_sample=E'let score = 0;\nscore = 10;\nconsole.log(score);\n\nconst name = "Анна";\nconsole.log(name);', code_output=E'10\nАнна' WHERE course_id='javascript' AND position=2;
UPDATE lessons SET code_lang='javascript', code_sample=E'function greet(name) {\n  return "Привет, " + name + "!";\n}\nconsole.log(greet("Мир"));', code_output=E'Привет, Мир!' WHERE course_id='javascript' AND position=3;
UPDATE lessons SET code_lang='javascript', code_sample=E'console.log(5 + 3);\nconsole.log(10 - 4);\nconsole.log(6 * 2);\nconsole.log(10 % 3);', code_output=E'8\n6\n12\n1' WHERE course_id='javascript' AND position=4;
UPDATE lessons SET code_lang='javascript', code_sample=E'let age = 20;\nif (age >= 18) {\n  console.log("Взрослый");\n} else {\n  console.log("Ребёнок");\n}', code_output=E'Взрослый' WHERE course_id='javascript' AND position=5;
UPDATE lessons SET code_lang='javascript', code_sample=E'for (let i = 0; i < 5; i++) {\n  console.log(i);\n}', code_output=E'0\n1\n2\n3\n4' WHERE course_id='javascript' AND position=6;
UPDATE lessons SET code_lang='javascript', code_sample=E'let fruits = ["яблоко", "банан"];\nfruits.push("груша");\nconsole.log(fruits);\nconsole.log(fruits.length);', code_output=E'["яблоко", "банан", "груша"]\n3' WHERE course_id='javascript' AND position=7;
UPDATE lessons SET code_lang='javascript', code_sample=E'let user = { name: "Алекс", age: 25 };\nconsole.log(user.name);\nuser.age = 26;\nconsole.log(user.age);', code_output=E'Алекс\n26' WHERE course_id='javascript' AND position=8;
UPDATE lessons SET code_lang='javascript', code_sample=E'// Пример обработки клика\nfunction handleClick() {\n  console.log("Кнопка нажата!");\n}\nhandleClick();', code_output=E'Кнопка нажата!' WHERE course_id='javascript' AND position=9;
UPDATE lessons SET code_lang='javascript', code_sample=E'const add = (a, b) => a + b;\nconsole.log(add(2, 3));\n\nlet name = "Алекс";\nconsole.log(`Привет, ${name}!`);', code_output=E'5\nПривет, Алекс!' WHERE course_id='javascript' AND position=10;
UPDATE lessons SET code_lang='javascript', code_sample=E'let nums = [1, 2, 3, 4];\nlet doubled = nums.map(n => n * 2);\nconsole.log(doubled);\nlet big = nums.filter(n => n > 2);\nconsole.log(big);', code_output=E'[2, 4, 6, 8]\n[3, 4]' WHERE course_id='javascript' AND position=11;
UPDATE lessons SET code_lang='javascript', code_sample=E'let n = 0;\nn++;\nn++;\nn++;\nconsole.log("Кликов: " + n);', code_output=E'Кликов: 3' WHERE course_id='javascript' AND position=12;